const RECYCLED_USER_PAGE_CAP: usize = 16384;

struct RecycledPages {
    pages: [usize; RECYCLED_USER_PAGE_CAP],
    len: usize,
}

impl RecycledPages {
    const fn new() -> Self {
        Self {
            pages: [0; RECYCLED_USER_PAGE_CAP],
            len: 0,
        }
    }

    fn push(&mut self, page: usize) {
        if self.len < RECYCLED_USER_PAGE_CAP {
            self.pages[self.len] = page;
            self.len += 1;
        }
    }

    fn pop(&mut self) -> Option<usize> {
        if self.len == 0 {
            None
        } else {
            self.len -= 1;
            Some(self.pages[self.len])
        }
    }
}

