extern "C" fn kernel_main() -> ! {
    let (free_start, free_size) = arch::memory_range();
    {
        let mut fa = FRAME_ALLOCATOR.lock();
        *fa = Some(BumpFrameAllocator::new(PhysAddr::new(free_start), free_size));
    }

    let heap_pages = 8192;
    {
        let mut fa = FRAME_ALLOCATOR.lock();
        if let Some(heap_start) = fa.as_mut().unwrap().alloc_contiguous(heap_pages) {
            unsafe { ALLOCATOR.0.lock().init(heap_start.as_usize(), heap_pages * PAGE_SIZE); }
        }
    }

    println!();
    println!("SockCore kernel boot");
    println!("arch={}", arch_name());

    #[cfg(target_arch = "riscv64")]
    {
        setup_kernel_page_table();
        arch::init_trap();
        // Get kernel satp for process model
        let ksatp: usize;
        unsafe { core::arch::asm!("csrr {}, satp", out(reg) ksatp); }
        crate::syscall::init_process(ksatp);
        test_ramfs();
        println!("trying ext4 mount...");
        if let Some(mut ext4) = mount_ext4() {
            runner::run_all(&mut ext4);
        } else {
            println!("ext4 mount failed, using builtin test");
            run_user_test();
        }
    }

    #[cfg(target_arch = "loongarch64")]
    {
        arch::init_trap();
        crate::syscall::init_process(0);
        println!("trying ext4 mount...");
        if let Some(mut ext4) = mount_ext4() {
            runner::run_all(&mut ext4);
        } else {
            println!("ext4 mount failed on LoongArch");
            println!("!TEST FINISH!");
            arch::arch_shutdown();
        }
    }
}

fn mount_ext4() -> Option<crate::fs::ext4::Ext4Fs> {
    use crate::driver::virtio_mmio::VirtIoBlk;
    use crate::fs::ext4::Ext4Fs;

    #[cfg(target_arch = "riscv64")]
    {
        for attempt in 0..3 {
            let Some(blk) = VirtIoBlk::init(0x10001000) else {
                continue;
            };
            let Some(mut ext4) = Ext4Fs::open(blk) else {
                continue;
            };
            if let Some((_ino, root)) = ext4.resolve("/") {
                let entries = ext4.read_dir(&root);
                crate::println!("ext4: / has {} entries", entries.len());
                if !entries.is_empty() {
                    return Some(ext4);
                }
            }
            crate::println!("ext4: empty root dir, retry mount {}", attempt + 1);
        }
        None
    }

    #[cfg(target_arch = "loongarch64")]
    {
        for attempt in 0..3 {
            let Some(blk) = VirtIoBlk::init_pci() else {
                continue;
            };
            let Some(mut ext4) = Ext4Fs::open(blk) else {
                continue;
            };
            if let Some((_ino, root)) = ext4.resolve("/") {
                let entries = ext4.read_dir(&root);
                crate::println!("ext4: / has {} entries", entries.len());
                if !entries.is_empty() {
                    return Some(ext4);
                }
            }
            crate::println!("ext4: empty root dir, retry mount {}", attempt + 1);
        }
        None
    }
}

