    let ctx = Arc::new(context::ProcessContext::new());
    let tty: Arc<dyn crate::fs::vfs::INode> = Arc::new(crate::fs::ramfs::RamFile::new());
    let stdout = FileHandle::console(tty.clone(), 1);
    let stdin = FileHandle::new(tty.clone(), 0);
