#[panic_handler]
fn panic(info: &PanicInfo) -> ! {
    crate::println!("KERNEL PANIC");
    if let Some(loc) = info.location() {
        crate::println!("  at {}:{}:{}", loc.file(), loc.line(), loc.column());
    }
    crate::arch::arch_shutdown();
}

